import * as crypto from "crypto";

/**
 * Split a base64 key string into 64-char PEM lines.
 * Throws if the key is empty or not valid base64 content.
 */
function splitBase64(key: string): string[] {
  const lines = key.match(/.{1,64}/g);
  if (!lines) {
    throw new Error("Invalid key material: empty or malformed base64 string");
  }
  return lines;
}

/**
 * Parse the baked-in license keys JSON.
 * At build time, tsdown `env` replaces process.env.BAKED_LICENSE_KEYS_JSON with a string literal.
 * At runtime (tests / unbaked), the env var is not set so this returns {}.
 */
function parseBakedLicenseKeys(): Record<string, string> {
  try {
    const json = process.env.BAKED_LICENSE_KEYS_JSON;
    if (!json) return {};
    const parsed: unknown = JSON.parse(json);
    if (typeof parsed === "object" && parsed !== null && !Array.isArray(parsed)) {
      return parsed as Record<string, string>;
    }
    return {};
  } catch {
    return {};
  }
}

/**
 * Master public key — root of trust.
 * Baked in at build time via tsdown `env` (replaces process.env.BAKED_MASTER_PUBLIC_KEY).
 * Not overridable at runtime — this is the root of the trust chain.
 */
export function getMasterPublicKey(): string | null {
  const baked = process.env.BAKED_MASTER_PUBLIC_KEY;
  return baked || null;
}

// License-signing keys — bundled at build time, augmented at runtime via /v1/keys.
export const LICENSE_PUBLIC_KEYS: Record<string, string> = parseBakedLicenseKeys();

// Runtime keys fetched from licensing.copilotkit.ai/v1/keys
const runtimeKeys: Record<string, string> = {};

/**
 * Get a public key by key ID.
 * Checks runtime keys first (network-delivered), then bundled keys.
 */
export function getPublicKey(keyId: string): string | null {
  return runtimeKeys[keyId] ?? LICENSE_PUBLIC_KEYS[keyId] ?? null;
}

/**
 * Add a runtime key fetched from the network.
 * Only call this after verifying the key's attestation.
 */
export function addRuntimeKey(keyId: string, publicKey: string): void {
  runtimeKeys[keyId] = publicKey;
}

/** Remove all runtime keys from the in-memory registry. */
export function clearRuntimeKeys(): void {
  for (const key of Object.keys(runtimeKeys)) {
    delete runtimeKeys[key];
  }
}

export interface KeyAttestationData {
  keyId: string;
  publicKey: string;
  attestationSig: string;
}

/**
 * Verify a key attestation against the master public key.
 * The attestation is a signature of `keyId:publicKey` by the master key.
 */
export function verifyKeyAttestation(attestation: KeyAttestationData): boolean {
  try {
    const masterKey = getMasterPublicKey();
    if (!masterKey) {
      return false;
    }

    const message = `${attestation.keyId}:${attestation.publicKey}`;
    const signature = Buffer.from(attestation.attestationSig, "base64");

    const pemKey =
      "-----BEGIN PUBLIC KEY-----\n" +
      splitBase64(masterKey).join("\n") +
      "\n-----END PUBLIC KEY-----";
    const publicKey = crypto.createPublicKey(pemKey);

    return crypto.verify(null, Buffer.from(message), publicKey, signature);
  } catch {
    return false;
  }
}
