import { verifyLicense, isFeatureEnabled } from "./verify";
import type { LicenseStatus, LicensePayload } from "./types";

const GRACE_PERIOD_DAYS = 7;

/**
 * Runtime-agnostic license checker that caches verification results
 * and re-evaluates expiration on each access for long-lived processes.
 */
export interface LicenseChecker {
  /** Get the current license status, re-evaluating expiration. */
  getStatus(): LicenseStatus;
  /** Check whether a specific feature is enabled. Returns true when no token (soft enforcement). */
  checkFeature(feature: string): boolean;
}

/**
 * Create a license checker that verifies the token once at construction
 * and re-evaluates expiration on each `getStatus()` call.
 *
 * When no token is provided, falls back to `COPILOTKIT_LICENSE_TOKEN` env var.
 * Missing/invalid tokens result in soft enforcement (features allowed, warnings emitted).
 */
export function createLicenseChecker(licenseToken?: string): LicenseChecker {
  const token = licenseToken ?? process.env.COPILOTKIT_LICENSE_TOKEN;

  let initialStatus: LicenseStatus;
  if (token) {
    initialStatus = verifyLicense(token);
    if (!initialStatus.valid) {
      console.warn(
        "\n" +
        "**********************************************************\n" +
        "*                                                        *\n" +
        `*  [CopilotKit] License error: ${(initialStatus.error ?? "unknown").padEnd(25)}*\n` +
        "*  Visit copilotkit.ai/pricing for a valid license.      *\n" +
        "*                                                        *\n" +
        "**********************************************************\n",
      );
    }
  } else {
    console.warn(
      "\n" +
      "**********************************************************\n" +
      "*                                                        *\n" +
      "*  [CopilotKit] No license token configured.             *\n" +
      "*  Visit copilotkit.ai/pricing to get a license.         *\n" +
      "*                                                        *\n" +
      "**********************************************************\n",
    );
    initialStatus = { valid: false, license: null, error: null, warningSeverity: "info" };
  }

  const cachedPayload: LicensePayload | null = initialStatus.license;
  const signatureValid: boolean = initialStatus.license !== null && initialStatus.error === null;

  function getStatus(): LicenseStatus {
    if (!cachedPayload || !signatureValid) return initialStatus;

    const expiresAt = new Date(cachedPayload.expires_at);
    const now = new Date();

    if (expiresAt >= now) {
      return { valid: true, license: cachedPayload, error: null, warningSeverity: "none" };
    }

    const daysSinceExpiry = Math.floor((now.getTime() - expiresAt.getTime()) / (24 * 60 * 60 * 1000));
    const graceRemaining = GRACE_PERIOD_DAYS - daysSinceExpiry;

    if (graceRemaining > 0) {
      return { valid: true, license: cachedPayload, error: null, graceRemaining, warningSeverity: "warning" };
    }

    return { valid: false, license: cachedPayload, error: "expired", warningSeverity: "critical" };
  }

  function checkFeature(feature: string): boolean {
    const status = getStatus();
    if (!status.license) return true;
    return isFeatureEnabled(status.license, feature);
  }

  return { getStatus, checkFeature };
}

/**
 * Generate a license warning HTTP header based on the checker's current status.
 * Returns null when no warning is needed.
 */
export function getLicenseWarningHeader(
  checker?: LicenseChecker,
): { key: string; value: string } | null {
  if (!checker) return null;
  const status = checker.getStatus();
  if (status.warningSeverity === "critical") {
    console.warn("[CopilotKit] License expired. Visit copilotkit.ai/pricing");
    return { key: "X-CopilotKit-License-Warning", value: status.error ?? "expired" };
  }
  if (status.warningSeverity === "warning") {
    console.warn(`[CopilotKit] License expires in ${status.graceRemaining} days. Please renew.`);
    return { key: "X-CopilotKit-License-Warning", value: "expiring" };
  }
  return null;
}
