interface FeatureDefinition {
  displayName: string;
  component?: boolean;
  runtime?: boolean;
}

export const LICENSED_FEATURES: Record<string, FeatureDefinition> = {
  chat: { displayName: "Chat", component: true },
  sidebar: { displayName: "Sidebar", component: true },
  popup: { displayName: "Popup", component: true },
  suggestions: { displayName: "Suggestions", component: true },
  agents: { displayName: "Agents", runtime: true },
  voice: { displayName: "Voice", component: true, runtime: true },
  frontend_tools: { displayName: "Frontend Tools", component: true },
  human_in_the_loop: { displayName: "Human-in-the-Loop", component: true },
  mcp_integration: { displayName: "MCP Integration", runtime: true },
  custom_activity_renderers: { displayName: "Activity Renderers", component: true },
  headless_ui: { displayName: "Headless UI", component: true },
  dev_console: { displayName: "Dev Console", component: true },
  guardrails: { displayName: "Guardrails", runtime: true },
};

export function getFeatureDisplayName(feature: string): string {
  return LICENSED_FEATURES[feature]?.displayName ?? feature;
}

export function isComponentFeature(feature: string): boolean {
  return LICENSED_FEATURES[feature]?.component === true;
}

export function isRuntimeFeature(feature: string): boolean {
  return LICENSED_FEATURES[feature]?.runtime === true;
}
