import * as crypto from "crypto";
import type { LicensePayload, LicenseStatus } from "./types";
import { getPublicKey } from "./keystore";

const GRACE_PERIOD_DAYS = 7;

/**
 * Split a base64 key string into 64-char PEM lines.
 * Throws if the key is empty or not valid base64 content.
 */
function splitBase64(key: string): string[] {
  const lines = key.match(/.{1,64}/g);
  if (!lines) {
    throw new Error("Invalid key material: empty or malformed base64 string");
  }
  return lines;
}

/**
 * Decode a base64url-encoded string to a Buffer.
 */
function base64UrlDecode(data: string): Buffer {
  let padded = data.replace(/-/g, "+").replace(/_/g, "/");
  const padding = (4 - (padded.length % 4)) % 4;
  padded += "=".repeat(padding);
  return Buffer.from(padded, "base64");
}

/**
 * Parse a 3-part license token: header.payload.signature
 * Header format: { alg: "EdDSA", typ: "LIC", kid: "<key_id>" }
 */
function parseToken(token: string): {
  header: { alg: string; typ: string; kid: string };
  payload: LicensePayload;
  signature: Buffer;
  signingInput: string;
} | null {
  if (!token || typeof token !== "string") return null;
  const parts = token.split(".");
  if (parts.length !== 3) return null;

  try {
    const [headerPart, payloadPart, signaturePart] = parts as [string, string, string];
    const header = JSON.parse(base64UrlDecode(headerPart).toString("utf-8"));
    const payload = JSON.parse(base64UrlDecode(payloadPart).toString("utf-8"));
    const signature = base64UrlDecode(signaturePart);

    if (header.alg !== "EdDSA" || header.typ !== "LIC") return null;

    return { header, payload, signature, signingInput: `${headerPart}.${payloadPart}` };
  } catch {
    return null;
  }
}

/**
 * Verify a license token offline using Ed25519 signature.
 * This is a pure function — no caching. Callers should cache the result.
 */
export function verifyLicense(token: string): LicenseStatus {
  const parsed = parseToken(token);
  if (!parsed) {
    return { valid: false, license: null, error: "parse_error", warningSeverity: "critical" };
  }

  const publicKeyBase64 = getPublicKey(parsed.header.kid);
  if (!publicKeyBase64) {
    return {
      valid: false,
      license: parsed.payload,
      error: "unknown_key",
      warningSeverity: "critical",
    };
  }

  try {
    const pemKey =
      "-----BEGIN PUBLIC KEY-----\n" +
      splitBase64(publicKeyBase64).join("\n") +
      "\n-----END PUBLIC KEY-----";
    const publicKey = crypto.createPublicKey(pemKey);
    const isValid = crypto.verify(null, Buffer.from(parsed.signingInput), publicKey, parsed.signature);

    if (!isValid) {
      return {
        valid: false,
        license: parsed.payload,
        error: "invalid_signature",
        warningSeverity: "critical",
      };
    }
  } catch {
    return {
      valid: false,
      license: parsed.payload,
      error: "invalid_signature",
      warningSeverity: "critical",
    };
  }

  // Check expiration
  const expiresAt = new Date(parsed.payload.expires_at);
  const now = new Date();
  if (expiresAt < now) {
    const daysSinceExpiry = Math.floor((now.getTime() - expiresAt.getTime()) / (24 * 60 * 60 * 1000));
    const graceRemaining = GRACE_PERIOD_DAYS - daysSinceExpiry;

    if (graceRemaining <= 0) {
      return {
        valid: false,
        license: parsed.payload,
        error: "expired",
        warningSeverity: "critical",
      };
    }

    return {
      valid: true,
      license: parsed.payload,
      error: null,
      graceRemaining,
      warningSeverity: "warning",
    };
  }

  return { valid: true, license: parsed.payload, error: null, warningSeverity: "none" };
}

/**
 * Check whether a specific feature is enabled in the license.
 * Returns false if the license is null or the feature is not present (deny by default).
 */
export function isFeatureEnabled(license: LicensePayload | null, feature: string): boolean {
  if (!license) return false;
  return license.features[feature] === true;
}

/**
 * Get a numeric feature limit from the license.
 * Returns null if the license is null, the feature is missing, or the value is not a number.
 */
export function getFeatureLimit(license: LicensePayload | null, feature: string): number | null {
  if (!license) return null;
  const value = license.features[feature];
  return typeof value === "number" ? value : null;
}
